scwin.f_Retrieve2 = async function () {
  let ret;
  ret = await $c.gus.cfValidate($p, [ed_coCd]);
  if (!ret) return;
  if (!$c.gus.cfIsAfterDate($p, ed_collMoneyFromDate.getValue(), ed_collMoneyToDate.getValue())) {
    $c.gus.cfAlertMsg($p, "입금일자 시작일자는 만기일자보다 이전 날짜 이어야 합니다.");
    ed_collMoneyToDate.focus();
    return;
  }

  // 조회 조건의 필수 입력 사항 체크
  if (ed_crn.getValue().trim() == "" && ed_sclntNo.getValue().trim() == "") {
    // 필수 조회조건 입력 여부(거래처명) Check
    if (lc_collMoneyCntSht.getValue() != "01") {
      ret = await $c.gus.cfValidate($p, [ed_sclntNo]);
      if (!ret) {
        return;
      }
    }
  }

  // 조회 조건의 필수 입력 사항 체크
  ret = await $c.gus.cfValidate($p, [ed_collMoneyFromDate, ed_collMoneyToDate]);
  if (!ret) {
    return;
  }

  //부서조회용 날짜(상단 그리드와 검색 변수명이 중복되어, 조회시에 다른 dataset로 보냄)
  //dma_searchCollMoney.ClearData();
  //dma_searchCollMoney.ImportData(ds_searchAcctRecv.ExportData(1, ds_searchAcctRecv.CountRow, false)); //수금수단 조회용 TEMP DATA에 넣는다.  
  //dma_searchCollMoney.setJSON(dma_searchAcctRecv.getJSON()); bind 가 달라서 따로 지정
  dma_searchCollMoney.setJSON(scwin.rtnSearchParam('01'));
  dma_searchCollMoney.set("queryDeptSearchStDate", ed_collMoneyFromDate.getValue());
  dma_searchCollMoney.set("queryDeptSearchEndDate", ed_collMoneyToDate.getValue());
  // 수금수단 조회 조건용 TR

  //tr_searchCollMoney.Post();
  $c.sbm.execute($p, sbm_searchCollMoney);

  //수금내역 선택금액 초기화
  ed_selectAmtCollMoney.setValue("0");
  ed_selectAmtFcrcCollMoney.setValue("0.00");
  dma_searchAcctRecv.set("repClntNo", "T");

  // 환차손익 초기화
  ed_gap.setValue("0");
  $c.gus.cfDisable($p, [ed_gap]);
  ed_initAmt.setValue("0");
  ed_acctDeptCd.setValue("");
  ed_acctDeptNm.setValue("");
  ed_commiSsionAmt.setValue("0");
  ed_commiSsionAmtFcrc.setValue("0.00");
};
