//-------------------------------------------------------------------------
// 각 Argument에 따른 PopUp을 호출 한다.
// 1:조회->거래처, 2:조회->수금귀속부서, 3:조회->통장번호
// code변수는 각 항목별 검색요청 값이다.
//-------------------------------------------------------------------------
scwin.f_openPopUp = function (orgObjCd, orgObjNm, select_code, flag) {
  // POPUP 돋보기 클릭시는 모든값을 조회 할 수 있도록 한다. flag:ALL일 경우는 돋보기 클릭한것임.
  // 넘어온 OBJ가 EMEdit인지 TextBox인지 구분한다.
  if (flag == "ALL") {
    cd = "";
    nm = "";
  } else {
    cd = orgObjCd.getValue();
    nm = orgObjNm.getValue();
  }
  let param = "";
  switch (select_code) {
    // 조회조건용 거래처 PopUp 호출
    case '1':
      param = "" + ed_coCd.getValue(); //자회사 회계시스템 추가사항

      udc_sclntNo.setSelectId("retrieveClntEmpNoList");
      udc_sclntNo.cfCommonPopUp(scwin.udc_sclntNo_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 거래처(모든 거래처를 다 조회한다.) 

      break;
    // 조회조건용 수금부서 PopUp 호출
    case '2':
      param = ed_FromDate.getValue().trim() + "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",,,"; //자회사 회계시스템 추가사항
      udc_sacctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
      udc_sacctDeptCd.cfCommonPopUp(scwin.udc_sacctDeptCd_cb, cd, nm, "T", null, null, null, null, param, "450", "500", null, null); // 귀속부서			

      break;
    case '3':
      param = ",,,,," + ed_coCd.getValue(); //자회사 회계시스템 추가사항
      udc_sbankbookCd.setSelectId("retrieveBankBookCdInfo");
      udc_sbankbookCd.cfCommonPopUp(scwin.udc_sbankbookCd_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 통장명

      break;
    case '4':
      // 사업자번호
      udc_crn.setSelectId("retrieveCrnInfo");
      udc_crn.cfCommonPopUp(scwin.udc_crn_cb, cd, nm, "T", null, null, null, null, null, null, null, null, null); //사업자번호

      break;
    case '5':
      // 선수금청구귀속부서 
      param = "," + ed_coCd.getValue() + "," + scwin.txtCoClsCd + ",0"; //자회사 회계시스템 추가사항
      udc_acctDeptCd.setSelectId("retrieveAcctDeptCdInfo6");
      udc_acctDeptCd.cfCommonPopUp(scwin.udc_acctDeptCd_cb, cd, nm, "T", null, null, null, null, param, null, null, null, null); // 귀속부서			

      break;
    case '6':
      // 수금요청 승인자 지정 
      param = ",,,"; //자회사 회계시스템 추가사항

      udc_apprvEmpNo.setSelectId("retrieveMailList2");
      udc_apprvEmpNo.cfCommonPopUp(scwin.udc_apprvEmpNo_cb, ed_apprvEmpNo.getValue(), "", "F", null, null, null, null, param, "450", "500", null, null);
      break;
    default:
      $c.gus.cfAlertMsg($p, "잘못된 Function호출 입니다. 관리자에게 문의하시기 바랍니다.");
      break;
  }
};

