//-------------------------------------------------------------------------
// 수금등록 저장시
//-------------------------------------------------------------------------
scwin.f_Save = async function () {
  //AsIs 바인딩 데이터들 세팅해준다.
  scwin.setBingDataSet();
  // 사용변수 선언
  let acctRecvAmtFcrc = 0; // 채권외화선택금액
  let acctRecvCheckUsd = 0; // 채권외화 통화코드 선택여부
  let acctRecvCheckKrw = 0; // 채권원화 통화코드 선택여부
  let acctRecvFcrcCheck = 0; // 채권외화 통화코드 체크

  let collMoneyAmtFcrc = 0; // 수금외화선택금액
  let collMoneyCheckUsd = 0; // 수금외화 통화코드 선택여부
  let collMoneyCheckKrw = 0; // 수금원화 통화코드 선택여부
  let collMoneyFcrcCheck = 0; // 수금외화 통화코드 체크

  let ret;
  let acctRecvCollMoneyFcrcCheck = 0; // 채권외화,수금외화 통화코드 체크

  // 보험대차시 수수료 입력여부 체크 => 수수료 입력 불가
  if (!scwin.f_CheckInsrLndcar()) return;
  // 수금 등록시 보험대차 채권은 1개만 수금 가능 : 보험대차채권+일반채권 Or 보험대차채권+보험대차채권 불가(2011.10.28 김준곤)
  if (!scwin.f_CheckInsrLndcarAcctMulti()) return;

  // 저장시 필수 입력 사항 Check
  ret = await $c.gus.cfValidate($p, [ed_wrkDt, ed_sacctDeptCd]);
  if (!ret) {
    return;
  }

  //승인자 필수입력 체크
  if (scwin.vLoginCoCd == "000" || scwin.vLoginCoCd == "029") {
    ret = await $c.gus.cfValidate($p, [ed_apprvEmpNo]);
    if (!ret) {
      return;
    }
  }

  // 필수 입력 여부 Check(부서 날짜 검색시 이용됨)
  ret = await $c.gus.cfValidate($p, [ed_collMoneyFromDate, ed_collMoneyToDate]);
  if (!ret) {
    return;
  }

  //귀속부서 및 거래처가 변경되었을 경우 재조회후 수금처리 가능하게 함.

  if (!scwin.checkSearch) {
    $c.gus.cfAlertMsg($p, "필수 입력사항인 거래처,귀속부서코드가 변경되었습니다.\n재조회 하신후 수금처리 하시기 바랍니다.");
    return;
  }
  if (!scwin.checkSearch1) {
    $c.gus.cfAlertMsg($p, "필수 입력사항인 거래처,귀속부서코드가 변경되었습니다.\n재조회 하신후 수금처리 하시기 바랍니다.");
    return;
  }

  //작업일자보다 입금일자가 크면 작업일자를 현재일자로 변경, 입금일자 월이 서로 다른것은 처리 안됨
  for (var i = 0; i < ds_collMoney.getRowCount(); i++) {
    if (ds_collMoney.getCellData(i, "num") == "T") {
      if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") != "") {
        //입금일자가 있을때
        if (dma_addCollMoney.get("wrkDt").substring(0, 6) < ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6)) {
          $c.gus.cfAlertMsg($p, "작업일자가 입금일자 보다 이전 월이면 처리 할 수 없습니다.\n" + "작업일자를 현재일자로 변경하겠습니다.");
          ed_wrkDt.setValue(scwin.strToDate);
          return;
        }
      } else if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") == "" && ds_collMoney.getCellData(i, "changeDt") != "") {
        //입금급일자가 없고 선수금전환일자가 있을때
        if (dma_addCollMoney.get("wrkDt").substring(0, 6) < ds_collMoney.getCellData(i, "changeDt").substring(0, 6)) {
          $c.gus.cfAlertMsg($p, "작업일자가 선수금전환일자 보다 이전 월이면 처리 할 수 없습니다.\n" + "작업일자를 현재일자로 변경하겠습니다.");
          ed_wrkDt.setValue(scwin.strToDate);
          return;
        }
      }
      for (var j = 0; j < ds_collMoney.getRowCount(); j++) {
        if (ds_collMoney.getCellData(j, "num") == "T") {
          if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") != "") {
            //입금일자가 있을때
            if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") != "") {
              //입금일자가 있을때
              if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6) != ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            } else if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") && ds_collMoney.getCellData(j, "changeDt") != "") {
              ////입금일자가 없고 선수금전환일자가 있을때
              if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6) != ds_collMoney.getCellData(j, "changeDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            }
          } else if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") == "" && ds_collMoney.getCellData(i, "changeDt") != "") {
            ////입금일자가 없고 선수금전환일자가 있을때
            if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") != "") {
              //입금일자가 있을때
              if (ds_collMoney.getCellData(i, "changeDt").substring(0, 6) != ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            } else if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") && ds_collMoney.getCellData(j, "changeDt") != "") {
              ////입금일자가 없고 선수금전환일자가 있을때
              if (ds_collMoney.getCellData(i, "changeDt").substring(0, 6) != ds_collMoney.getCellData(j, "changeDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            }
          }
        }
      }
    }
  }

  // 채권수금정리일경우
  if (lc_acctRecvClsCd.getValue() == "01") {
    let iinitAmt = parseInt(dma_addCollMoney.get("initAmt")); //선수금 금액
    let icommiSsionAmt = parseInt(dma_addCollMoney.get("commiSsionAmt")); // 수수료금액(원화)
    let icommiSsionAmtFcrc = parseFloat(dma_addCollMoney.get("commiSsionAmtFcrc")); // 수수료(외화)
    let gapAmt = parseFloat(dma_addCollMoney.get("gapAmt")); // 환차손익 금액

    scwin.f_retrieveJudgeCommiSsionAmt();

    //수수료 권한. 여객쪽은 금액 10만원 이상도 수수료 입력가능.
    if (dma_judgeCommiSsionAmt.get("col1") == "200") {
      scwin.gJudgeYnCommiSsionAmt = "1";
    } else {
      scwin.gJudgeYnCommiSsionAmt = "0";
    }

    // 선수금,수수료(원),수수료(외)는 0보다 커야한다.
    if (iinitAmt < 0) {
      $c.gus.cfAlertMsg($p, "선수금 금액은 0이상 이어야 합니다.");
      return;
    }
    if (icommiSsionAmt < 0) {
      $c.gus.cfAlertMsg($p, "수수료(원)는 0이상 이어야 합니다.");
      return;
    }
    //수수료 입력시  100000원 이상을 초과하여 입력할 수 없음 .본사채권파트 만 입력이 가능하다 (2007.03.26-윤영훈 )
    //여객쪽은 100000원 이상 초과하여 입력가능하게. (2010.03.02 - 신한나)
    if (icommiSsionAmt > 100000) {
      if (scwin.gJudgeYn == "0") {
        if (scwin.gJudgeYnCommiSsionAmt == "0") {
          $c.gus.cfAlertMsg($p, "수수료(원)는 100000이상 초과하여  입력 할 수 없습니다 .");
          return;
        }
      }
    }
    // 신용관리파트가 아니고 금액이 5만원이 넘을시에는 에러처리한다.
    if (scwin.gJudgeYn == "0" && Math.abs(scwin.gapAmt) >= '50000') {
      $c.win.alert($p, "외환차손이 5만원이상 발생시에는 신용관리팀만 처리할 수 있습니다");
      return;
    }
    if (icommiSsionAmtFcrc < 0) {
      $c.gus.cfAlertMsg($p, "수수료(외화)는 0이상 이어야 합니다.");
      return;
    }

    // 체크박스에 체크가 안되고 수정만 일어난 데이타Set은 Undo시킨다.
    // 가수금/선수금에 대해서 금액을 수정해서 입력 가능하기 때문에 들어간 로직
    for (var ii = 0; ii < ds_collMoney.getRowCount(); ii++) {
      if (ds_collMoney.getCellData(ii, "num") != "T") {
        //ds_collMoney.Undo(ii);
        ds_collMoney.undoRow(ii);
      }
    }

    //    alert("ed_sclntNo"+ed_sclntNo.text);   

    // 선택한 외화채권 금액을 누적한다.
    for (var ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
      if (ds_acctRecv.getCellData(ii, "num") == "T") {
        acctRecvAmtFcrc += parseFloat(ds_acctRecv.getCellData(ii, "ramtFcrc")); //외화금액 누적
        //채권의 통화코드가 USD가 선택되었는지 확인
        if (ds_acctRecv.getCellData(ii, "crcCd") != ACConstants.KRW) {
          acctRecvCheckUsd++;
        }
        // 채권의 통화코드가 KRW가 선택되었는지 확인
        if (ds_acctRecv.getCellData(ii, "crcCd") == ACConstants.KRW) {
          acctRecvCheckKrw++;
        }
      }
    }

    // 선택한 수금 외화금액을 누적한다.
    for (var ii = 0; ii < ds_collMoney.getRowCount(); ii++) {
      if (ds_collMoney.getCellData(ii, "num") == "T") {
        collMoneyAmtFcrc += parseFloat(ds_collMoney.getCellData(ii, "setlAmtFcrc")); //수금 외화금액 누적
        //채권의 통화코드가 USD가 선택되었는지 확인
        if (ds_collMoney.getCellData(ii, "crcCd") != ACConstants.KRW) {
          collMoneyCheckUsd++;
        }
        // 채권의 통화코드가 KRW가 선택되었는지 확인
        if (ds_collMoney.getCellData(ii, "crcCd") == ACConstants.KRW) {
          collMoneyCheckKrw++;
        }
      }
    }

    // 채권에 외화원화를 선택할경우 수금정리가 안됨.
    if (acctRecvCheckUsd > 0 && acctRecvCheckKrw > 0) {
      $c.gus.cfAlertMsg($p, "외화 수금처리시는 채권항목의 통화코드가 모두 KRW이 아니어야 가능합니다.\n선택하신 채권항목을 확인하시기 바랍니다.");
      return;
    }

    // 수금에 외화 원화를 선택할경우 수금 정리가 안됨
    if (collMoneyCheckUsd > 0 && collMoneyCheckKrw > 0) {
      $c.gus.cfAlertMsg($p, "외화 수금처리시는 수금항목의 통화코드가 모두 KRW이 아니어야 가능합니다\n선택하신 수금항목을 확인하시기 바랍니다.");
      return;
    }

    // 선택한 외화채권 금액이 있으면 외화 통화가 같은지 체크.
    if (acctRecvCheckUsd > 0) {
      for (var ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
          for (var jj = ii + 1; jj < ds_acctRecv.getRowCount(); jj++) {
            if (ds_acctRecv.getCellData(jj, "num") == "T") {
              if (ds_acctRecv.getCellData(ii, "crcCd") != ds_acctRecv.getCellData(jj, "crcCd")) {
                acctRecvFcrcCheck++;
              }
            }
          }
        }
      }
    }

    // 선택한 외화수금 금액이 있으면 외화 통화가 같은지 체크.
    if (collMoneyCheckUsd > 0) {
      for (var ii = 0; ii < ds_collMoney.getRowCount(); ii++) {
        if (ds_collMoney.getCellData(ii, "num") == "T") {
          for (var jj = ii + 1; jj <= ds_collMoney.getRowCount(); jj++) {
            if (ds_collMoney.getCellData(jj, "num") == "T") {
              if (ds_collMoney.getCellData(ii, "crcCd") != ds_collMoney.getCellData(jj, "crcCd")) {
                collMoneyFcrcCheck++;
              }
            }
          }
        }
      }
    }

    // 채권에 외화를 선택할경우 통화코드가 다르면 수금정리가 안됨.
    if (acctRecvFcrcCheck > 0) {
      $c.gus.cfAlertMsg($p, "외화 수금처리시는 채권항목의 통화코드가 모두 같아야 가능합니다.\n선택하신 채권항목을 확인하시기 바랍니다.");
      return;
    }

    // 수금에 외화 원화를 선택할경우 통화코드가 다르면 수금 정리가 안됨
    if (collMoneyFcrcCheck > 0) {
      $c.gus.cfAlertMsg($p, "외화 수금처리시는 수금항목의 통화코드가 모두같아야 가능합니다\n선택하신 수금항목을 확인하시기 바랍니다.");
      return;
    }

    // 선택한 외화채권 외화수금 금액이 있으면 채권과 수금의 통화가 같은지 체크.
    if (acctRecvCheckUsd > 0 && collMoneyCheckUsd > 0) {
      for (var ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
          for (var jj = 0; jj < ds_collMoney.getRowCount(); jj++) {
            if (ds_collMoney.getCellData(jj, "num") == "T") {
              if (ds_acctRecv.getCellData(ii, "crcCd") != ds_collMoney.getCellData(jj, "crcCd")) {
                acctRecvCollMoneyFcrcCheck++;
              }
            }
          }
        }
      }
    }

    // 채권과 수금의  통화코드가 다르면 수금정리가 안됨.
    if (acctRecvCollMoneyFcrcCheck > 0) {
      $c.gus.cfAlertMsg($p, "외화 수금처리시는 채권, 수금항목의 통화코드가  모두 같아야 가능합니다.\n선택하신 채권, 수금항목을 확인하시기 바랍니다.");
      return;
    }

    // 외화 수수료 입력시는 원화수수료와 선수금을 입력 할수 없음
    if (icommiSsionAmtFcrc > 0) {
      if (iinitAmt > 0) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 선수금액을 입력 하실 수 없습니다.");
        return;
      }
      if (icommiSsionAmt > 0) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 원화 수수료를 입력 하실 수 없습니다.");
        return;
      }
      if (gapAmt != 0) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 환차손익을 입력 하실 수 없습니다.");
        return;
      }
    }

    // 외화 수수료 입력시는 채권외화 금액과 수금외화 금액이 동일해야 처리 가능함.
    if (icommiSsionAmtFcrc > 0) {
      if (acctRecvCheckUsd > 0 && collMoneyCheckKrw > 0) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 채권,수금 항목의 통화코드가 모두 KRW이 아니어야 합니다.");
        return;
      }
      if (collMoneyCheckUsd > 0 && acctRecvCheckKrw > 0) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 채권,수금 항목의 통화코드가 모두 KRW이 아니어야 합니다.");
        return;
      }
      if (Math.round(acctRecvAmtFcrc * 100) / 100 != Math.round((collMoneyAmtFcrc + icommiSsionAmtFcrc) * 100) / 100) {
        $c.gus.cfAlertMsg($p, "외화 수수료 입력시는 채권외화금액 = 수금외화금액+외화수수료 금액이 동일해야 수금처리가 가능합니다.");
        return;
      }
    }
    let gapAmtLos = 0;
    let gapAmtPrf = 0;
    if (gapAmt < 0) {
      gapAmtLos = gapAmt * -1;
    } else {
      gapAmtPrf = gapAmt;
    }

    // 처리할 채권 금액 합산
    let iAcctRecvAmt = iinitAmt + parseInt(ed_selectAmt.getValue()) + gapAmtPrf;
    // 처리할 수금 금액 합산
    let iCollMoneyAmt = icommiSsionAmt + parseInt(ed_selectAmtCollMoney.getValue()) + gapAmtLos;
    //			alert(iAcctRecvAmt)
    //			alert(iCollMoneyAmt)
    // 선수금과 수수료를 둘다 입력하여 수금처리를 할 수 없다.
    if (iinitAmt > 0 && icommiSsionAmt > 0 && gapAmt != 0) {
      $c.gus.cfAlertMsg($p, "선수금과 수수료를 둘다 입력한 상태에서 수금처리를 할 수 없습니다.");
      return;
    }
    if (iinitAmt > 0 || icommiSsionAmt > 0 || gapAmt != 0) {
      if (iAcctRecvAmt != iCollMoneyAmt) {
        $c.gus.cfAlertMsg($p, "추가내용 입력시는 채권금액과 수금금액이 동일하여야 합니다.");
        return;
      }
    }
    // 채권이나 수금쪽에 Check 여부 확인
    let intAccountReceivable = 0; // 채권선택한 갯수 확인
    let intCollectionOfMoney = 0; // 수금선택한 갯수 확인
    let intAcctRecvAmt = 0; // 채권 선택금액 합계
    let intCollMoneyAmt = 0; // 수금 선택금액 합계
    let intCollMoneyAmtFcrc = 0; // 수금 (외화)선택금액 합계
    let checkBillReceivable = 0; // 수금항목중 받을어음 선택 여부확인
    let checkSuspInitAmt = 0; // 수금항목중 가수/선수금 선택 여부 확인
    let checkInitAmt = 0; // 선수금 선택여부 확인
    let intAcctRecvUsd = 0; // 채권의 통화코드가 KRW를  선택안했는지 여부확인

    // 선택한 채권 금액을 구한다.
    for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
      if (ds_acctRecv.getCellData(i, "num") == "T") {
        intAccountReceivable++;
        intAcctRecvAmt += ds_acctRecv.getCellData(i, "ramt");
        if (ds_acctRecv.getCellData(i, "crcCd") != ACConstants.KRW) {
          intAcctRecvUsd++;
          if (iinitAmt > 0 || icommiSsionAmt > 0) {
            //cfAlertMsg("선수금 및 수수료를 입력하실 경우는 채권의 통화코드가 KRW가 아닌것을 선택하실 수 없습니다. 채권내역을 확인하시기 바랍니다.");
            //return;
          }
        }
      }
    }

    // 선택한 어음 금액 및 수금항목중 어음을 선택했는지 여부를 확인한다.
    for (var i = 0; i < ds_collMoney.getRowCount(); i++) {
      if (ds_collMoney.getCellData(i, "num") == "T") {
        intCollectionOfMoney++;
        intCollMoneyAmt += ds_collMoney.getCellData(i, "setlAmt"); // 수금 원화금액 누적
        intCollMoneyAmtFcrc += parseFloat(ds_collMoney.getCellData(i, "setlAmtFcrc")); // 수금 외화금액 누적
        // 받을 어음을 선택했는지 여부 확인
        if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_CHECK || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_STOCK || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_ELECT || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_PROMISE) {
          checkBillReceivable++;
          // 선수금을 선택했는지 여부 확인
        } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_INITAMT) {
          checkSuspInitAmt++; //가수/선수 선택여부
          checkInitAmt++; // 선수금 선택여부
          // 가수금을 선택했는지 여부 확인
        } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_SUS_RECV) {
          checkSuspInitAmt++;
          // 계정코드가 어음,가수,선수가 아닐경우는 선택항목에 오류가 있는것임.
        } else {
          $c.gus.cfAlertMsg($p, "수금항목중 선택하신 항목에 문제가 있습니다.\n전산실로 연락 주시기 바랍니다");
          return;
        }
        if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") > ed_wrkDt.getValue()) {
          $c.gus.cfAlertMsg($p, "입금일자가 작업일자보다 크면 수금처리를 할 수 없습니다.");
          return;
        }
        if (ds_collMoney.getCellData(i, "changeDt") > ed_wrkDt.getValue()) {
          $c.gus.cfAlertMsg($p, "선수금 전환일자가 작업일자보다 크면 수금처리를 할 수 없습니다.");
          return;
        }

        // 통화코드가 USD일 경우는 받을어음수금처리를 할 수 없음.
        // 2008년 1월 29일 받을어음 통화코드에 관계없어 수금처리할수있게 변경
        //		if ( intAcctRecvUsd > 0) {
        //			if ( ds_collMoney.NameValue(i,"acctCd") == "<%=ACConstants.ACCTCD_BILLRECEIVABLE_CHECK%>" ||
        //				 ds_collMoney.NameValue(i,"acctCd") == "<%=ACConstants.ACCTCD_BILLRECEIVABLE_STOCK%>" ||
        //				 ds_collMoney.NameValue(i,"acctCd") == "<%=ACConstants.ACCTCD_BILLRECEIVABLE_ELECT%>" ||
        //				 ds_collMoney.NameValue(i,"acctCd") == "<%=ACConstants.ACCTCD_BILLRECEIVABLE_PROMISE%>" ) {
        //				 cfAlertMsg("수금내역에 받을어음 선택시는 채권내역에 통화코드가 KRW인것을 선택 해야만 합니다..\n채권 선택내역을 확인하시기 바랍니다");
        //				 return;
        //			}
        //		}
      }
    }
    // 선수금 선택후 선수금전환은 못하게 막음
    if (checkSuspInitAmt > 0 && iinitAmt > 0) {
      $c.gus.cfAlertMsg($p, "가수금에서 선수금 전환은 가수금처리화면에서 처리 하세요.");
      return;
    }

    // 선수금 선택후 선수금전환은 못하게 막음
    if (checkInitAmt > 0 && iinitAmt > 0) {
      $c.gus.cfAlertMsg($p, "선수금 선택후 선수금 전환금액을 입력하시면 수금처리가 불가능합니다.");
      return;
    }
    if (intAccountReceivable == 0) {
      $c.gus.cfAlertMsg($p, "채권 항목은 최소 1개이상 선택 하셔야 합니다.");
      return;
    }
    if (intCollectionOfMoney == 0) {
      $c.gus.cfAlertMsg($p, "수금 항목은 최소 1개이상 선택 하셔야 합니다.");
      return;
    }
    if (intAccountReceivable >= 2 && intCollectionOfMoney >= 2) {
      $c.gus.cfAlertMsg($p, "채권항목 수금항목중 한개의 항목은 1개만 선택 하셔야 합니다.");
      return;
    }

    // 추가 내역중 선수금은 가/선수금의 수금내역을 선택해야만 처리가 가능함.
    // (2006.04.03) 받을어음 정리시 선수금은 입력가능하게 로직 변경함.
    if (checkBillReceivable > 0 && (icommiSsionAmt > 0 || gapAmt != 0)) {
      $c.gus.cfAlertMsg($p, "받을어음 선택시에는 수수료를 입력하실 수 없습니다.");
      return;
    }

    // 수금항목이 받을어음에 대한 것일경우는 채권 총금액이 수금의 총금액보다 크거나 같아야 된다.
    if (checkBillReceivable > 0) {
      //채권선택총금액이 수금총금액 보다 작을 경우 처리 불가
      if (parseInt(intAcctRecvAmt) + iinitAmt + gapAmtPrf < parseInt(intCollMoneyAmt) + icommiSsionAmt + gapAmtLos) {
        $c.gus.cfAlertMsg($p, "수금항목중 받을어음 선택시는 채권금액이 수금금액보다 커야 합니다.");
        return;
      }
    }

    // 수수료(외화) 입력시 수수료 금액만으로 채권이 정리되는지 확인함.
    // 수수료금액만으로 채권이 정리 될수는없음.
    if (icommiSsionAmtFcrc > 0) {
      let tempCollMoneyAmtFcrc = intCollMoneyAmtFcrc; // 선택한 수금금액(외화)
      let tempCheckCmis = 0;
      let tempCheckColl = 0;
      for (var ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
          tempCollMoneyAmtFcrc -= parseFloat(ds_acctRecv.getCellData(ii, "ramtFcrc"));
          // 채권선택 금액 이상의 수금금액을 선택했는지 여부 확인
          if (tempCheckCmis > 0) {
            tempCheckColl++;
          }
        }
        // 선택 채권금액이 종료됨
        if (tempCollMoneyAmtFcrc <= 0) {
          tempCheckCmis++;
        }
        // 수수료만으로 채권이 정리되는 경우일경우 오류 처리
        if (tempCheckColl > 0 && tempCheckCmis > 0) {
          $c.gus.cfAlertMsg($p, "선택하신 채권중 일부가 전액 수수료(외화)로 처리됩니다.\n선택하신 채권과 수수료(외화) 입력 금액을 확인하시기 바랍니다.");
          return;
        }
      }
    }

    // 수수료(원화) 입력시 수수료 금액만으로 채권이 정리되는지 확인함.
    if (icommiSsionAmt > 0) {
      let tempCollMoneyAmt = intCollMoneyAmt; // 선택한 수금 금액
      let tempCheckCmis = 0;
      let tempCheckColl = 0;
      for (let ii = 0; ii < ds_acctRecv.getRowCount(); ii++) {
        if (ds_acctRecv.getCellData(ii, "num") == "T") {
          tempCollMoneyAmt = tempCollMoneyAmt - parseInt(ds_acctRecv.getCellData(ii, "ramt"));
          // 채권선택 금액 이상의 수금금액을 선택했는지 여부 확인
          if (tempCheckCmis > 0) {
            tempCheckColl++;
          }
        }
        // 선택 채권금액이 종료됨
        if (tempCollMoneyAmt <= 0) {
          tempCheckCmis++;
        }
        // 수수료만으로 채권이 정리되는 경우일경우 오류 처리
        if (tempCheckColl > 0 && tempCheckCmis > 0) {
          $c.gus.cfAlertMsg($p, "선택하신 채권중 일부가 전액 수수료로 처리됩니다.\n선택하신 채권과 수수료 입력 금액을 확인하시기 바랍니다.");
          return;
        }
      }
    }

    // 선수금 입력시 선수금 금액만으로 수금항목이 정리되는지 확인함.
    if (iinitAmt > 0) {
      let tempAcctRecvAmt = intAcctRecvAmt; // 선택한 채권금액
      let tempCheckInitAmt = 0;
      let tempCheckAcct = 0;
      for (var ii = 0; ii < ds_collMoney.getRowCount(); ii++) {
        if (ds_collMoney.getCellData(ii, "num") == "T") {
          tempAcctRecvAmt = tempAcctRecvAmt - parseInt(ds_collMoney.getCellData(ii, "setlAmt"));
          // 수금선택금액 이상의 채권금액을 선택했는지 여부 확인
          if (tempCheckInitAmt > 0) {
            tempCheckAcct++;
          }
        }
        // 입력 수금금액이 종료 되었음.
        if (tempAcctRecvAmt <= 0) {
          tempCheckInitAmt++;
        }
        // 수수료만으로 채권이 정리되는 경우일경우 오류 처리
        if (tempCheckAcct > 0 && tempCheckInitAmt > 0) {
          $c.gus.cfAlertMsg($p, "선택하신 수금항목중 일부가 전액 선수금 처리됩니다.\n선택하신 수금항목과 선수금 입력 금액을 확인하시기 바랍니다.");
          return;
        }
      }
    }
    if (gapAmt != 0) {
      let acctRecvCountCheck = 0;
      // 선택한 채권 건수를 누적한다.
      for (var pp = 0; pp < ds_acctRecv.getRowCount(); pp++) {
        if (ds_acctRecv.getCellData(pp, "num") == "T") {
          acctRecvCountCheck++;
        }
      }
      if (acctRecvCountCheck > 1) {
        $c.gus.cfAlertMsg($p, "환차손익을 입력한 경우 채권은 1건만 처리 할 수 있습니다.");
        return;
      }
    }

    //	 alert(ds_acctRecv.NameValue(1,"clntNo"));

    ///////////////////////////////////////20081203 전영훈 추가 시작//////////////////////////////////////////
    /* 1. 수금수단에 선택된 계정이 받을어음일 경우, TB_FM211, TB_FM212에 INSERT시 TB_FM215에 BILG_ACCT_DEPT_CD 필드값과
          TB_FM111의 ACCT_DEPT_CD 필드값이 다를경우 ‘외상매출금 청구귀속부서와 받을어음 청구귀속부서가 다릅니다.’ 메시지 처리
       2. 계정이 선수금-일반일 경우, TB_FM211, TB_FM212에 INSERT시 TB_FM215에 BILG_ACCT_DEPT_CD 필드값과
            TB_FM213에 ACCT_DEPT_CD 필드값과  다를경우 ‘외상매출금 청구귀속부서와 선수금 청구귀속부서가 다릅니다.’ 메시지 처리
         3. 선수금 금액이 0이 아니면 선수금 귀속부서 필수 체크
    */
    if (ed_initAmt.getValue() != "0" && ed_acctDeptCd.getValue() == "") {
      $c.gus.cfAlertMsg($p, "선수금 금액이 0원이 아니면, 선수금 청구부서는 필수 입력 항목 입니다.");
      ed_acctDeptCd.focus();
      return;
    }
    for (var k = 0; k < ds_collMoney.getRowCount(); k++) {
      if (ds_collMoney.getCellData(k, "num") == "T") {
        if (ds_collMoney.getCellData(k, "acctCd") == "1110430") {
          // 1110430 받을 어음 

          for (var m = 0; m < ds_acctRecv.getRowCount(); m++) {
            if (ds_acctRecv.getCellData(m, "num") == "T") {
              if (ds_collMoney.getCellData(k, "acctDeptCd") != ds_acctRecv.getCellData(m, "bilgAcctDeptCd")) {
                $c.win.alert($p, "채권내역(대변) " + m + " 번째 줄의 외상매출금 청구귀속부서 : " + ds_acctRecv.getCellData(m, "bilgAcctDeptCd") + " 과 " + "수금내역(차변) " + k + " 번째 줄의 " + ds_collMoney.getCellData(k, "") + " 청구귀속부서 : " + ds_collMoney.getCellData(k, "acctDeptCd") + "가 다릅니다.");
                return false;
                break;
              }
            }
          } //for
        }
      }
    }
    ///////////////////////////////////20081203 전영훈 추가 끝///////////////////////////////////////////////////

    // 저장확인
    ret = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (ret == true) {
      // 조회부분 헤더에 거래처가 없을경우 체크된 첫번째 데이터의 거래처 번호를  헤더에 셋팅
      if (!ed_sclntNo.getValue()) {
        var clntNo = null;
        for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
          if (ds_acctRecv.getCellData(i, "num") === "T") {
            clntNo = ds_acctRecv.getCellData(i, "clntNo");
            break;
          }
        }
        if (!clntNo && ds_acctRecv.getRowCount() > 0) {
          clntNo = ds_acctRecv.getCellData(0, "clntNo");
        }
        if (clntNo) {
          ed_sclntNo.setValue(clntNo);
          ds_addCollMoney.setCellData(0, "clntNo", clntNo);
        }
      }
      //tr_saveAcctRecvCollMoney.Post();
      $c.sbm.execute($p, sbm_saveAcctRecvCollMoney);
    }
    // 부도어음 수금 정리일경우		
  } else if (lc_acctRecvClsCd.getValue() == "02") {
    // 채권이나 수금쪽에 Check 여부 확인
    intAccountReceivable = 0;
    intCollectionOfMoney = 0;
    let intAcctRecvAmt = 0;
    let intCollMoneyAmt = 0;
    checkBillReceivable = 0; // 수금항목중 받을어음 선택 여부확인
    let checkSuspInitAmt = 0; // 수금항목중 가수/선수금 선택 여부 확인
    let checkInitAmt = 0; // 선수금 선택여부 확인
    collMoneyCheckUsd = 0; // 수금외화 통화코드 선택여부

    // 체크박스에 체크가 안되고 수정만 일어난 데이타Set은 Undo시킨다.
    // 가수금/선수금에 대해서 금액을 수정해서 입력 가능하기 때문에 들어간 로직

    for (let ii = 0; ii < ds_collMoney.getRowCount(); ii++) {
      if (ds_collMoney.getCellData(ii, "num") != "T") {
        //ds_collMoney.Undo(ii);
        //$c.data.undoRow(ds_collMoney, "Y");
        ds_collMoney.undoRow(ii);
      }
    }

    // 선택한 채권 금액을 구한다.
    for (var i = 0; i < ds_billRecvDisho.getRowCount(); i++) {
      if (ds_billRecvDisho.getCellData(i, "num") == "T") {
        intAccountReceivable++;
        intAcctRecvAmt += ds_billRecvDisho.getCellData(i, "prtAmt");
      }
    }

    // 선택한 어음 금액 및 수금항목중 어음을 선택했는지 여부를 확인한다.
    for (var i = 0; i < ds_collMoney.getRowCount(); i++) {
      if (ds_collMoney.getCellData(i, "num") == "T") {
        intCollectionOfMoney++;
        intCollMoneyAmt += ds_collMoney.getCellData(i, "setlAmt");
        // 받을 어음을 선택했는지 여부 확인
        if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_CHECK || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_STOCK || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_ELECT || ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_BILLRECEIVABLE_PROMISE) {
          checkBillReceivable++;
          // 선수금을 선택했는지 여부 확인
        } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_INITAMT) {
          checkSuspInitAmt++; //가수/선수 선택여부
          checkInitAmt++; // 선수금 선택여부
          // 가수금을 선택했는지 여부 확인
        } else if (ds_collMoney.getCellData(i, "acctCd") == ACConstants.ACCTCD_SUS_RECV) {
          checkSuspInitAmt++;
        }

        // 가수금/선수금 항목중에 통화가 USD를 선택 여부 확인
        if (ds_collMoney.getCellData(i, "crcCd") != ACConstants.KRW) {
          collMoneyCheckUsd++;
        }
      }
    }
    if (collMoneyCheckUsd > 0) {
      $c.gus.cfAlertMsg($p, "부도어음 처리시는 수금항목중 통화코드가 KRW가 아닌 항목은 선택 하실 수 없습니다.");
      return;
    }
    if (intAccountReceivable == 0) {
      $c.gus.cfAlertMsg($p, "채권 항목은 최소 1개이상 선택 하셔야 합니다.");
      return;
    }
    if (intCollectionOfMoney == 0) {
      $c.gus.cfAlertMsg($p, "수금 항목은 최소 1개이상 선택 하셔야 합니다.");
      return;
    }
    if (intAccountReceivable >= 2 && intCollectionOfMoney >= 2) {
      $c.gus.cfAlertMsg($p, "채권항목 수금항목중 한개의 항목은 1개만 선택 하셔야 합니다.");
      return;
    }
    if (checkBillReceivable > 0) {
      $c.gus.cfAlertMsg($p, "부도어음 처리시는 받을어음을 선택 하실 수 없습니다.");
      return;
    }
    if (ds_addCollMoney.getCellData(0, "clntNo") == "") {
      if (ed_sclntNo.getValue() == "") {
        $c.win.alert($p, "거래처는 필수 입력 항목 입니다");
        return;
      }
      ds_addCollMoney.setCellData(0, "clntNo", ed_sclntNo.getValue());
    }
    ret = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (ret == true) {
      // 조회부분 헤더에 거래처가 없을경우 체크된 첫번째 데이터의 거래처 번호를  헤더에 셋팅
      if (!ed_sclntNo.getValue()) {
        clntNo = null;
        for (var i = 0; i < ds_billRecvDisho.getRowCount(); i++) {
          if (ds_billRecvDisho.getCellData(i, "num") === "T") {
            clntNo = ds_billRecvDisho.getCellData(i, "clntNo");
            break;
          }
        }
        if (!clntNo && ds_billRecvDisho.getRowCount() > 0) {
          clntNo = ds_billRecvDisho.getCellData(0, "clntNo");
        }
        if (clntNo) {
          ed_sclntNo.setValue(clntNo);
          ds_addCollMoney.setCellData(0, "clntNo", clntNo);
        }
      }
      //tr_saveBillRecvDisho.Post();
      //부도어음 처리 수금등록 저장용 TR
      $c.sbm.execute($p, sbm_saveBillRecvDisho);
    }
  }
};

//-------------------------------------------------------------------------
// 체크박스 클릭이벤트 발생시 해당 금액을 화면에 표시하는 함수(수금대상)
//-------------------------------------------------------------------------
scwin.collMoneyCheck = function (Row) {
  // AsIs는 lower로 읽는게 된다.
  // ToBe는 안됨 camel 로 변환 해라 checknum -> checkNum

  if (ds_collMoney.getCellData(Row, "num") == "T" && ds_collMoney.getCellData(Row, "checkNum") == "F") {
    ed_selectAmtCollMoney.setValue(parseInt(ed_selectAmtCollMoney.getValue()) + parseInt(ds_collMoney.getCellData(Row, "setlAmt")));
    ed_selectAmtFcrcCollMoney.setValue((parseFloat(ed_selectAmtFcrcCollMoney.getValue()) + parseFloat(ds_collMoney.getCellData(Row, "setlAmtFcrc"))).toFixed(2));
    ds_collMoney.setCellData(Row, "checkNum", "T");
  } else if (ds_collMoney.getCellData(Row, "num") == "F" && ds_collMoney.getCellData(Row, "checkNum") == "T") {
    ed_selectAmtCollMoney.setValue(parseInt(ed_selectAmtCollMoney.getValue()) - parseInt(ds_collMoney.getCellData(Row, "setlAmt")));
    ed_selectAmtFcrcCollMoney.setValue((parseFloat(ed_selectAmtFcrcCollMoney.getValue()) - parseFloat(ds_collMoney.getCellData(Row, "setlAmtFcrc"))).toFixed(2));
    ds_collMoney.setCellData(Row, "checkNum", "F");
  }
};

//-------------------------------------------------------------------------
// 잡손/익처리
//-------------------------------------------------------------------------
scwin.f_EtcLossProc = async function () {
  let ret;
  ret = await $c.gus.cfValidate($p, [ed_sclntNo, ed_wrkDt, ed_FromDate, ed_ToDate, ed_sacctDeptCd]);
  if (!ret) {
    return;
  }
  if (lc_acctRecvClsCd.getValue() == "02") {
    $c.win.alert($p, "잡손/익처리는 채권내역에서만 가능합니다.");
    return;
  }

  //귀속부서 및 거래처가 변경되었을 경우 재조회 후 잡손실 처리가 가능한게 함.
  if (scwin.hid_acctDeptCd.trim() == "" || scwin.hid_acctDeptCd != ed_sacctDeptCd.getValue().trim()) {
    $c.gus.cfAlertMsg($p, "청구(수금)부서가 변경되어 잡손/익 처리가 불가능합니다. 재조회후 처리 하시기 바랍니다.");
    return;
  }
  if (scwin.hid_clntNo.trim() == "" || scwin.hid_clntNo != ed_sclntNo.getValue().trim()) {
    $c.gus.cfAlertMsg($p, "거래처가 변경되어 잡손/익 처리가 불가능합니다. 재조회후 처리 하시기 바랍니다.");
    return;
  }

  // 채권이나 수금쪽에 Check 여부 확인
  let intAccountReceivable = 0;

  // 선택한 채권 금액을 구한다.
  for (let i = 0; i < ds_acctRecv.getRowCount(); i++) {
    if (ds_acctRecv.getCellData(i, "num") == "T") {
      intAccountReceivable++;
    }
  }
  if (intAccountReceivable == 0) {
    $c.gus.cfAlertMsg($p, "채권 항목은 최소 1개이상 선택 하셔야 합니다.");
    return;
  }

  //- 금액인 경우 잡이익처리, + 금액인 경우 잡손실처리
  //동시에 처리 불가능.
  let plus = 0;
  let minus = 0;
  for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
    if (ds_acctRecv.getCellData(i, "num") == "T") {
      if (ds_acctRecv.getCellData(i, "ramt") < 1) {
        minus++;
      } else if (ds_acctRecv.getCellData(i, "ramt") > 0) {
        plus++;
      }
    }
  }
  if (plus != 0 && minus != 0) {
    $c.win.alert($p, "잡손처리와 잡익처리는 동시에 처리하실수 없습니다..");
    return;
  }

  //작업일자보다 입금일자가 크면 작업일자를 현재일자로 변경, 입금일자 월이 서로 다른것은 처리 안됨
  for (var i = 0; i < ds_collMoney.getRowCount(); i++) {
    if (ds_collMoney.getCellData(i, "num") == "T") {
      if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") != "") {
        //입금일자가 있을때
        //if (dma_addCollMoney.get("wrkDt").substring(0, 6) < ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6)) {
        //multi binding 안되므로 binding 대상으로 바꿔 넣는다.
        if (ed_wrkDt.getValue().substring(0, 6) < ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6)) {
          $c.gus.cfAlertMsg($p, "작업일자가 입금일자 보다 이전 월이면 처리 할 수 없습니다.\n" + "작업일자를 현재일자로 변경하겠습니다.");
          ed_wrkDt.setValue(scwin.strToDate);
          return;
        }
      } else if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") == "" && ds_collMoney.getCellData(i, "changeDt") != "") {
        //입금급일자가 없고 선수금전환일자가 있을때
        //if (dma_addCollMoney.get("wrkDt").substring(0, 6) < ds_collMoney.getCellData(i, "changeDt").substring(0, 6)) {
        if (ed_wrkDt.getValue().substring(0, 6) < ds_collMoney.getCellData(i, "changeDt").substring(0, 6)) {
          $c.gus.cfAlertMsg($p, "작업일자가 선수금전환일자 보다 이전 월이면 처리 할 수 없습니다.\n" + "작업일자를 현재일자로 변경하겠습니다.");
          ed_wrkDt.setValue(scwin.strToDate);
          return;
        }
      }
      for (var j = 0; j < ds_collMoney.getRowCount(); j++) {
        if (ds_collMoney.getCellData(j, "num") == "T") {
          if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") != "") {
            //입금일자가 있을때
            if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") != "") {
              //입금일자가 있을때
              if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6) != ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            } else if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") && ds_collMoney.getCellData(j, "changeDt") != "") {
              ////입금일자가 없고 선수금전환일자가 있을때
              if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt").substring(0, 6) != ds_collMoney.getCellData(j, "changeDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            }
          } else if (ds_collMoney.getCellData(i, "susRecvInitamtOutbrDt") == "" && ds_collMoney.getCellData(i, "changeDt") != "") {
            ////입금일자가 없고 선수금전환일자가 있을때
            if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") != "") {
              //입금일자가 있을때
              if (ds_collMoney.getCellData(i, "changeDt").substring(0, 6) != ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            } else if (ds_collMoney.getCellData(j, "susRecvInitamtOutbrDt") && ds_collMoney.getCellData(j, "changeDt") != "") {
              ////입금일자가 없고 선수금전환일자가 있을때
              if (ds_collMoney.getCellData(i, "changeDt").substring(0, 6) != ds_collMoney.getCellData(j, "changeDt").substring(0, 6)) {
                $c.gus.cfAlertMsg($p, "입금일자(선수금전환일자)의 월이 서로 다른것은 같이 처리 할 수 없습니다.");
                return;
              }
            }
          }
        }
      }
    }
  }
  let ramt;
  if (plus != 0) {
    ramt = 0;
    for (let i = 0; i < ds_acctRecv.getRowCount(); i++) {
      //잡손실은  10000원 이상을 초과할 수 없음
      //	alert(ds_acctRecv.NameValue(1,"ramt"));
      if (ds_acctRecv.getCellData(i, "num") == "T") {
        ramt = Number(ramt) + Number(ds_acctRecv.getCellData(i, "ramt"));
      }
    }

    //gJudgeYn ==  "0" && 
    //수금사항등록 에서의 잡손은 10000원이상 초과 할 수 없음.
    //이상인 금액은 채권잡손/익등록 화면에서 -
    if (ramt > 10000) {
      $c.gus.cfAlertMsg($p, "잡손등록은 10000원 이상 초과 할 수 없습니다 .");
      return;
    }
    ret = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (ret == true) {
      dma_addAcctRecvEtcLoss.set("acctCd", "6120220");
      //tr_saveAcctRecvEtcLoss.Post();
      // 채권잡손처리 저장용 TR
      $c.sbm.execute($p, sbm_saveAcctRecvEtcLoss);
      ed_wrkDt.setValue(scwin.strToDate); // 추가내역 작업일자 초기
    }
  } else if (minus != 0) {
    ramt = 0;
    for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
      //잡이익은  10000원 이상을 초과할 수 없음
      //	alert(ds_acctRecv.NameValue(1,"ramt"));
      if (ds_acctRecv.getCellData(i, "num") == "T") {
        ramt = ramt + ds_acctRecv.getCellData(i, "ramt");
      }
    }
    if (ramt < -10000) {
      $c.gus.cfAlertMsg($p, "잡이익등록은   10000원이상 초과 할 수 없습니다 .");
      return;
    }
    ret = await $c.win.confirm($p, MSG_CM_CRM_001);
    if (ret == true) {
      dma_addAcctRecvEtcLoss.set("acctCd", "6110232");
      //tr_saveAcctRecvEtcProfit.Post();
      //채권잡이익처리 저장용 TR
      $c.sbm.execute($p, sbm_saveAcctRecvEtcProfit);
      ed_wrkDt.setValue(scwin.strToDate); // 추가내역 작업일자 초기
    }
  }
};
