scwin.gr_acctRecv_onheaderclick = function (headerId) {
  let sum = 0;
  let sumFcrc = 0;
  scwin.bCheck = scwin.bCheck == "0" ? "1" : "0";
  if (headerId == "hNum") {
    var checkedLen = 0;
    for (var idx = 0; idx < ds_acctRecv.getRowCount(); idx++) {
      if (ds_acctRecv.getCellData(idx, "num") == "T") {
        checkedLen++;
        break;
      }
    }
    if (checkedLen > 0) {
      for (i = 0; i < ds_acctRecv.getRowCount(); i++) {
        ds_acctRecv.setCellData(i, "num", "T");
        sum = sum + Number(ds_acctRecv.getCellData(i, "ramt"));
        sumFcrc = sumFcrc + Number(ds_acctRecv.getCellData(i, "ramtFcrc"));
        ds_acctRecv.setCellData(i, "checkNum", "T");
      }
    } else {
      for (i = 0; i < ds_acctRecv.CountRow; i++) {
        ds_acctRecv.setCellData(i, "num", "F");
        ds_acctRecv.setCellData(i, "checkNum", "F");
      }
      sum = 0;
      sumFcrc = 0;
    }
  }
  ed_selectAmt.setValue(sum);
  ed_selectAmtFcrc.setValue(sumFcrc);
};
