scwin.gr_collMoney_oncellclick = function (Row, columnIndex, Colid) {
  if (Colid == "num") {
    // 체크박스 클릭시 이벤트 처리(금액계산)
    scwin.collMoneyCheck(Row);

    // 그리드 체크시 카운트값 초기화
    var chkA = 0;
    var chkB = 0;
    var crcCd1 = "";
    var crcCd2 = "";

    // 채권내역 그리드
    for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
      if (ds_acctRecv.getCellData(i, "num") == "T") {
        chkA++;
      }
    }

    // 수금내역 그리드
    for (var j = 0; j <= ds_collMoney.getRowCount(); j++) {
      if (ds_collMoney.getCellData(j, "num") == "T") {
        chkB++;
      }
    }
    if (chkA != 0 && chkB != 0) {
      // 수금, 채권중 하나식은 선택했을 경우 둘중 하나는 원화, 하나는 외화일 경우
      for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
        if (ds_acctRecv.getCellData(i, "num") == "T") {
          crcCd1 = ds_acctRecv.getCellData(i, "crcCd");
        }
      }
      for (var j = 0; j <= ds_collMoney.getRowCount(); j++) {
        if (ds_collMoney.getCellData(j, "num") == "T") {
          crcCd2 = ds_collMoney.getCellData(j, "crcCd");
        }
      }
      if (crcCd1 != ACConstants.KRW && crcCd2 == ACConstants.KRW || crcCd1 == "<%=ACConstants.KRW%>" && crcCd2 != ACConstants.KRW) {
        ed_gap.setValue(ed_selectAmtCollMoney.getValue() - ed_selectAmt.getValue());
        $c.gus.cfEnable($p, ed_gap);
      } else {
        ed_gap.setValue(0);
        $c.gus.cfDisable($p, ed_gap);
      }
    }
  }

  // 잔액을 수정하기 위해서 클릭시
  if (Colid == "setlAmt" || Colid == "setlAmtFcrc") {
    // 가수금과 선수금계정만 수정이 가능하다.
    if (ds_collMoney.getCellData(Row, "acctCd") == ACConstants.ACCTCD_SUS_RECV || ds_collMoney.getCellData(Row, "acctCd") == ACConstants.ACCTCD_INITAMT) {
      gr_collMoney.setColumnReadOnly('setlAmt', false); //gr_collMoney.ColumnProp("setlAmt", "Edit") = "Any";
      gr_collMoney.setColumnReadOnly('setlAmtFcrc', false); //gr_collMoney.ColumnProp("setlAmtFcrc", "Edit") = "Any";

      // 환차손익에 금액을 표시
      $c.gus.cfEnable($p, ed_gap);
    } else {
      gr_collMoney.setColumnReadOnly(setlAmt, true); //gr_collMoney.ColumnProp("setlAmt", "Edit") = "None";
      gr_collMoney.setColumnReadOnly(setlAmtFcrc, true); //gr_collMoney.ColumnProp("setlAmtFcrc", "Edit") = "None";

      // 그리드 체크시 카운트값 초기화
      var chkA = 0;
      var chkB = 0;
      var crcCd1 = "";
      var crcCd2 = "";

      // 채권내역 그리드
      for (var i = 0; i < ds_acctRecv.getRowCount(); i++) {
        if (ds_acctRecv.getCellData(i, "num") == "T") {
          chkA++;
        }
      }

      // 수금내역 그리드
      for (var j = 0; j < ds_collMoney.getRowCount(); j++) {
        if (ds_collMoney.getCellData(j, "num") == "T") {
          chkB++;
        }
      }
      if (chkA != 0 && chkB != 0) {
        // 수금, 채권중 하나식은 선택했을 경우 둘중 하나는 원화, 하나는 외화일 경우
        for (var i = 0; i <= ds_acctRecv.getRowCount(); i++) {
          if (ds_acctRecv.getCellData(i, "num") == "T") {
            crcCd1 = ds_acctRecv.getCellData(i, "crcCd");
          }
        }
        for (var j = 0; j < ds_collMoney.getRowCount(); j++) {
          if (ds_collMoney.getCellData(j, "num") == "T") {
            crcCd2 = ds_collMoney.getCellData(j, "crcCd");
          }
        }
        if (crcCd1 != ACConstants.KRW && crcCd2 == ACConstants.KRW || crcCd1 == ACConstants.KRW && crcCd2 != ACConstants.KRW) {
          ed_gap.setValue(ed_selectAmtCollMoney.getValue() - ed_selectAmt.getValue());
          $c.gus.cfEnable($p, ed_gap);
        } else {
          ed_gap.setValue(0);
          $c.gus.cfDisable($p, ed_gap);
        }
      }
    }
  }
};
